const now = new Date();
const hour = now.getHours();

// Only call between 10 AM and 8 PM IST
if (hour < 10 || hour > 20) {
  return []; // No calls outside business hours
}

const items = $input.all();
return items.filter(item => {
  const scheduled = new Date(item.json.scheduled_time);
  return scheduled <= now && item.json.status === 'pending';
});

const name = $input.first().json.query.name || '';
const purpose = $input.first().json.query.purpose || 'follow_up';
const lang = $input.first().json.query.lang || 'en';
const machineDetected = $input.first().json.body.AnsweredBy;

// If voicemail detected, leave a short message
if (machineDetected === 'machine_end_other' || machineDetected === 'machine_end_beep') {
  return [{ json: {
    greeting: `Hi ${name}, this is Priya calling from the venue. We have a special offer for you this weekend. Please call us back at your convenience. Thank you!`,
    is_voicemail: true
  }}];
}

const templates = {
  booking_reminder: `Hi ${name}! This is Priya from the venue. I'm calling to confirm your reservation for tomorrow. Do you have a quick moment?`,
  follow_up: `Hello ${name}! This is Priya calling from the venue. We noticed you enquired about our services recently. I just wanted to check if you'd like to go ahead with a booking?`,
  event_promo: `Hi ${name}! This is Priya from the venue. We have an exciting event coming up this weekend and I thought of you. Do you have a minute?`,
  feedback: `Hi ${name}! This is Priya from the venue. You visited us recently and we'd love your quick feedback. Do you have 2 minutes?`,
  offer: `Hello ${name}! This is Priya from the venue. We have an exclusive offer just for our valued customers. Can I share the details with you?`
};

const greeting = templates[purpose] || templates.follow_up;

return [{ json: { greeting, is_voicemail: false, purpose, caller_name: name, detected_language: lang } }];
